const body = items[0].json.body || items[0].json;
const companyId = body.companyId;
const hrEmail = body.hrEmail;
const requests = body.requests || [];
if (!companyId || !hrEmail) {
  throw new Error('companyId and hrEmail are required for tenant-isolated leave digests');
}
const pending = requests.filter((request) => request.status === 'pending');
let html = '<h3>Awaiting Leave Approvals Summary</h3>';
html += '<table border="1" style="border-collapse: collapse; width:100%;">';
html += '<tr><th>Employee</th><th>Leave type</th><th>Duration</th></tr>';
pending.forEach((request) => {
  html += `<tr><td>${request.employeeName}</td><td>${request.leaveType}</td><td>${request.startDate} to ${request.endDate}</td></tr>`;
});
html += '</table>';
return [{ json: { companyId, hrEmail, shouldSend: pending.length > 0, htmlContent: html, count: pending.length } }];
